var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말 이 근처가 맞나요?","JPN":"本当にこの近くなのですか？","ENG":"Are you sure it's around here?","TWN":"真的在這附近嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"다리 뒤로 반쯤 무너진 건물 보이지? 바로 저기야.","JPN":"橋の向こうに半分崩れた建物が見えるでしょ？　そこだよ。","ENG":"See the half-collapsed building behind the bridge? That's it.","TWN":"有看到橋後面倒塌的建築物嗎？就是那個。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"일단 여기서부터 화려하게 화력난사를......!","JPN":"とりあえず、ここからド派手に火力乱射を……！","ENG":"I'll pour them a rain of fire from here first, then...","TWN":"總之先從這裡來個華麗的火力掃射……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 쇳덩어리 좀 치워요! 가급적 평화적으로 해결한다고 했잖아요!","JPN":"その鉄の塊はしまってください！　できるだけ平和に解決すると言ったはずですわ！","ENG":"Will you put that bulky thing away? I said we're going to handle this as peacefully as possible.","TWN":"把那個鐵塊拿開！不是說了要盡可能地和平解決嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"히잉~ 그런 건 재미없는데.","JPN":"え～っ、それじゃ面白くないのに。","ENG":"Boohoo! But that's no fun at all!","TWN":"嗚嗚～那樣很無聊了耶。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"일단 대화부터 해 볼 테니까 다들 따라오세요.","JPN":"まずは話し合いをしてみますので、ついて来てください。","ENG":"I'll try to reason with them first. You just follow me.","TWN":"總之我們先試著跟他們談談，大家跟我來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"너무 어두운데요?","JPN":"すごく暗いですわね。","ENG":"It's too dark here.","TWN":"這也太暗了吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 우리가 너무 늦어서 모두 떠나 버린 거 아닐까요?","JPN":"まさか、来るのが遅すぎてどこかへ行ってしまったかしら？","ENG":"Perhaps we came too late and they've all left.","TWN":"該不會是我們來太晚了，他們已經離開了吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄? 그런 것 치곤 냄새가 좀 이상한데......","JPN":"どうかな？　その割には嫌な匂いがするけど……","ENG":"I don’t know. This weird smell says differently.","TWN":"誰知道呢？但先不管這些，總覺得這裡的氣味有點奇怪……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"제게 랜턴이 있어요. 켜볼게요.","JPN":"ランタンがあるので、点けてみますね。","ENG":"Here is a lantern. Let's turn it on.","TWN":"我帶了提燈，打開來看看。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 뭐야 저건......? 시체......?","JPN":"あ、あれは……？　死体……？","ENG":"W-what are those? Corpses?","TWN":"這、這是什麼……？屍體……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고...... 시체에서 뭔가 자라나고 있어?","JPN":"そして……死体から何かが生えている？","ENG":"And there's something growing on them!","TWN":"而且……屍體上好像還長了什麼？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나 말대로 늦어버렸네. 조금 다른 의미긴 하지만.","JPN":"レジーナの言う通り、着くのが遅かったみたいだね。ちょっと別の意味でだけど。","ENG":"We were too late indeed, but in a very different sense.","TWN":"就如蕾佳娜大人所說，我們來晚了，不過意思稍微不太一樣。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 한가한 소리에요?!","JPN":"何をのんきなことを言ってるのですか！？","ENG":"What are you murmuring about?","TWN":"妳在說什麼風涼話啊？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저건 분명 침식체일 거에요! 당장 여기서 나가야......","JPN":"あれはきっと侵食体です！　すぐにここから出ないと……","ENG":"They must be Corrupted Objects! We have to get out of he—","TWN":"那明明是侵蝕體吧！我們得立刻從這裡離開……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......에델?","JPN":"……エデル？","ENG":"Edel?","TWN":"……艾瑟兒？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};